#!/usr/bin/env tsx
/**
 * T059 — per-rule `.jinja` file invariants check.
 *
 * Runs against the checked-in `packages/<grammar>/templates/*.jinja`
 * files. Fails with a non-zero exit code when:
 *
 *   1. Any file is missing the `@generated` comment header (detects
 *      hand-created files; hand-edits on existing files are caught
 *      by running codegen in CI and diffing — handled separately).
 *   2. Any file contains a forbidden Jinja construct from the
 *      authoring subset violation list (catches hand-edits that
 *      add `{% extends %}`, `{% macro %}`, `{% include %}`,
 *      `{% match %}`, or `{% set %}`).
 *   3. Any `.yaml` template file reappears under a templates dir
 *      (regression lock for the YAML format).
 *
 * Usage:
 *   npx tsx scripts/check-jinja-templates.ts
 *
 * Emits a one-line summary on success; prints each violation (with
 * file + matched text) and exits 1 on failure.
 */

import { readdirSync, readFileSync, statSync } from "node:fs";
import { join } from "node:path";

const GRAMMARS = ["rust", "typescript", "python"];
// Regex source (no `g` flag) — a fresh RegExp is built per-file with
// the `g` flag so `.exec()` state doesn't leak between files. A stale
// `lastIndex` would silently skip matches at early offsets on
// subsequent files.
const FORBIDDEN_SRC = /\{%-?\s*(extends|macro|include|match|set)\b/;
// Accept both whitespace-stripped (`{#-`) and plain (`{#`) comment
// openers. The emitter uses `{#-` so nested-render whitespace gets
// stripped at render time; legacy templates that were committed with
// the plain form (or are hand-authored fixtures) match the same check.
const HEADER_RE = /^\{#-?\s*@generated\s+by\s+@sittir\/codegen/;

interface Violation {
	file: string;
	kind: "missing-header" | "forbidden" | "yaml-regression";
	detail: string;
}

const violations: Violation[] = [];

for (const grammar of GRAMMARS) {
	const dir = join(`packages/${grammar}/templates`);
	let entries: string[];
	try {
		entries = readdirSync(dir);
	} catch {
		console.error(`skip: ${dir} not found`);
		continue;
	}
	for (const name of entries) {
		const path = join(dir, name);
		const stats = statSync(path);
		if (!stats.isFile()) continue;
		if (name.endsWith(".yaml") || name.endsWith(".yml")) {
			violations.push({
				file: path,
				kind: "yaml-regression",
				detail: "YAML template format was retired in feature 011 — remove this file",
			});
			continue;
		}
		if (!name.endsWith(".jinja")) continue;
		const body = readFileSync(path, "utf-8");
		if (!HEADER_RE.test(body)) {
			violations.push({
				file: path,
				kind: "missing-header",
				detail: "file lacks the `{# @generated by @sittir/codegen #}` header",
			});
		}
		// Per-file regex: fresh `lastIndex` state on every file.
		const forbidden = new RegExp(FORBIDDEN_SRC.source, "g");
		let m: RegExpExecArray | null;
		while ((m = forbidden.exec(body)) !== null) {
			violations.push({
				file: path,
				kind: "forbidden",
				detail: `forbidden construct: ${m[0]} (line ${lineOf(body, m.index)})`,
			});
		}
	}
}

function lineOf(text: string, offset: number): number {
	return text.slice(0, offset).split("\n").length;
}

if (violations.length === 0) {
	const count = GRAMMARS.map((g) => {
		try {
			return readdirSync(`packages/${g}/templates`).filter((f) => f.endsWith(".jinja")).length;
		} catch {
			return 0;
		}
	}).reduce((a, b) => a + b, 0);
	console.log(
		`✓ ${count} .jinja files — all headers present, no forbidden constructs, no YAML regressions`,
	);
	process.exit(0);
}

console.error(`✗ ${violations.length} violation(s):`);
for (const v of violations) {
	console.error(`  ${v.kind}: ${v.file}`);
	console.error(`    ${v.detail}`);
}
process.exit(1);
